package com.example.mfa.service;

import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Component
public class BackupCodeGenerator {

    private final SecureRandom random = new SecureRandom();

    public List<String> generateCodes(int count) {
        List<String> out = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            out.add(generateSingleCode());
        }
        return out;
    }

    private String generateSingleCode() {
        byte[] b = new byte[10];
        random.nextBytes(b);
        String s = Base64.getUrlEncoder().withoutPadding().encodeToString(b);
        s = s.replace("-", "").replace("_", "");
        if (s.length() > 16) s = s.substring(0, 16);
        return formatGrouped(s.toUpperCase());
    }

    private String formatGrouped(String s) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            if (i > 0 && i % 4 == 0) sb.append('-');
            sb.append(s.charAt(i));
        }
        return sb.toString();
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.MfaBackupCode;
import com.example.mfa.repo.BackupCodeRepository;
import com.example.mfa.repo.UserRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class MfaBackupCodeService {

    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final BackupCodeGenerator generator;
    private final PasswordEncoder passwordEncoder;

    public MfaBackupCodeService(UserRepository userRepository,
                                BackupCodeRepository backupCodeRepository,
                                BackupCodeGenerator generator,
                                PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.generator = generator;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(Long userId, int count) {
        AppUser user = userRepository.findById(userId).orElseThrow();
        user.setMfaEnabled(true);
        userRepository.save(user);

        backupCodeRepository.deleteByUserId(userId);

        List<String> plain = generator.generateCodes(count);
        List<MfaBackupCode> entities = new ArrayList<>(count);
        for (String p : plain) {
            MfaBackupCode c = new MfaBackupCode();
            c.setUser(user);
            c.setCodeHash(passwordEncoder.encode(normalize(p)));
            c.setUsed(false);
            c.setCreatedAt(Instant.now());
            entities.add(c);
        }
        backupCodeRepository.saveAll(entities);
        return plain;
    }

    @Transactional(readOnly = true)
    public long remainingCodes(Long userId) {
        return backupCodeRepository.countByUserIdAndUsedFalse(userId);
    }

    @Transactional
    public boolean consumeBackupCode(String username, String code) {
        AppUser user = userRepository.findByUsername(username).orElseThrow();
        if (!user.isMfaEnabled()) return false;

        String normalized = normalize(code);
        List<MfaBackupCode> active = backupCodeRepository.findActiveByUserIdForUpdate(user.getId());
        for (MfaBackupCode c : active) {
            if (passwordEncoder.matches(normalized, c.getCodeHash())) {
                c.setUsed(true);
                c.setUsedAt(Instant.now());
                backupCodeRepository.save(c);
                return true;
            }
        }
        return false;
    }

    private String normalize(String code) {
        if (code == null) return "";
        return code.trim().replaceAll("[^A-Za-z0-9]", "").toUpperCase();
    }
}

package com.example.mfa.web;

import com.example.mfa.repo.UserRepository;
import com.example.mfa.service.MfaBackupCodeService;
import jakarta.validation.constraints.Max;
import jakarta.validation.constraints.Min;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

import java.util.List;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final MfaBackupCodeService backupCodeService;
    private final UserRepository userRepository;

    public MfaController(MfaBackupCodeService backupCodeService, UserRepository userRepository) {
        this.backupCodeService = backupCodeService;
        this.userRepository = userRepository;
    }

    public static class EnableMfaRequest {
        @NotNull
        private Long userId;

        @Min(1)
        @Max(50)
        private int backupCodeCount = 10;

        public Long getUserId() { return userId; }
        public void setUserId(Long userId) { this.userId = userId; }

        public int getBackupCodeCount() { return backupCodeCount; }
        public void setBackupCodeCount(int backupCodeCount) { this.backupCodeCount = backupCodeCount; }
    }

    public static class EnableMfaResponse {
        private Long userId;
        private boolean mfaEnabled;
        private List<String> backupCodes;

        public EnableMfaResponse(Long userId, boolean mfaEnabled, List<String> backupCodes) {
            this.userId = userId;
            this.mfaEnabled = mfaEnabled;
            this.backupCodes = backupCodes;
        }

        public Long getUserId() { return userId; }
        public boolean isMfaEnabled() { return mfaEnabled; }
        public List<String> getBackupCodes() { return backupCodes; }
    }

    public static class BackupCodeAuthRequest {
        @NotBlank
        private String username;

        @NotBlank
        private String backupCode;

        public String getUsername() { return username; }
        public void setUsername(String username) { this.username = username; }

        public String getBackupCode() { return backupCode; }
        public void setBackupCode(String backupCode) { this.backupCode = backupCode; }
    }

    public static class BackupCodeAuthResponse {
        private String username;
        private boolean authenticated;
        private long remainingBackupCodes;

        public BackupCodeAuthResponse(String username, boolean authenticated, long remainingBackupCodes) {
            this.username = username;
            this.authenticated = authenticated;
            this.remainingBackupCodes = remainingBackupCodes;
        }

        public String getUsername() { return username; }
        public boolean isAuthenticated() { return authenticated; }
        public long getRemainingBackupCodes() { return remainingBackupCodes; }
    }

    @PostMapping("/enable")
    public EnableMfaResponse enable(@RequestBody EnableMfaRequest req) {
        if (req.getUserId() == null) throw new ResponseStatusException(HttpStatus.BAD_REQUEST, "userId required");
        if (!userRepository.existsById(req.getUserId())) throw new ResponseStatusException(HttpStatus.NOT_FOUND, "user not found");
        List<String> codes = backupCodeService.enableMfaAndGenerateBackupCodes(req.getUserId(), req.getBackupCodeCount());
        return new EnableMfaResponse(req.getUserId(), true, codes);
    }

    @PostMapping("/backup-code/auth")
    public BackupCodeAuthResponse authWithBackupCode(@RequestBody BackupCodeAuthRequest req) {
        boolean ok;
        try {
            ok = backupCodeService.consumeBackupCode(req.getUsername(), req.getBackupCode());
        } catch (Exception e) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "invalid credentials");
        }
        long remaining = 0;
        try {
            remaining = userRepository.findByUsername(req.getUsername())
                    .map(u -> backupCodeService.remainingCodes(u.getId()))
                    .orElse(0L);
        } catch (Exception ignored) {
        }
        if (!ok) throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "invalid backup code");
        return new BackupCodeAuthResponse(req.getUsername(), true, remaining);
    }
}

package com.example.mfa.web;

import com.example.mfa.model.AppUser;
import com.example.mfa.repo.UserRepository;
import jakarta.validation.constraints.NotBlank;
import org.springframework.http.HttpStatus;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ResponseStatusException;

import java.time.Instant;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;

    public UserController(UserRepository userRepository, PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
    }

    public static class CreateUserRequest {
        @NotBlank
        private String username;
        @NotBlank
        private String password;

        public String getUsername() { return username; }
        public void setUsername(String username) { this.username = username; }

        public String getPassword() { return password; }
        public void setPassword(String password) { this.password = password; }
    }

    public static class UserResponse {
        private Long id;
        private String username;
        private boolean mfaEnabled;
        private Instant createdAt;

        public UserResponse(Long id, String username, boolean mfaEnabled, Instant createdAt) {
            this.id = id;
            this.username = username;
            this.mfaEnabled = mfaEnabled;
            this.createdAt = createdAt;
        }

        public Long getId() { return id; }
        public String getUsername() { return username; }
        public boolean isMfaEnabled() { return mfaEnabled; }
        public Instant getCreatedAt() { return createdAt; }
    }

    @PostMapping
    public UserResponse create(@RequestBody CreateUserRequest req) {
        if (userRepository.findByUsername(req.getUsername()).isPresent()) {
            throw new ResponseStatusException(HttpStatus.CONFLICT, "username already exists");
        }
        AppUser u = new AppUser();
        u.setUsername(req.getUsername());
        u.setPasswordHash(passwordEncoder.encode(req.getPassword()));
        u.setMfaEnabled(false);
        u.setCreatedAt(Instant.now());
        u = userRepository.save(u);
        return new UserResponse(u.getId(), u.getUsername(), u.isMfaEnabled(), u.getCreatedAt());
    }

    @GetMapping("/{id}")
    public UserResponse get(@PathVariable Long id) {
        AppUser u = userRepository.findById(id).orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "not found"));
        return new UserResponse(u.getId(), u.getUsername(), u.isMfaEnabled(), u.getCreatedAt());
    }
}

package com.example.mfa.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {
    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        return http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth.anyRequest().permitAll())
                .httpBasic(Customizer.withDefaults())
                .build();
    }
}

